const { ApolloServer, gql, AuthenticationError, ForbiddenError } = require('apollo-server-express');
const express = require('express');
const jwt = require('jsonwebtoken');
const { Pool } = require('pg');
const { createHash } = require('crypto');
const rateLimit = require('express-rate-limit');
const { validate } = require('uuid');

const SECRET_KEY = process.env.JWT_SECRET || 'your-secret-key-here';
const DB_CONFIG = {
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT || 5432,
};

const pool = new Pool(DB_CONFIG);

const typeDefs = gql`
  type User {
    id: ID!
    username: String!
    email: String!
    createdAt: String!
    isActive: Boolean!
  }

  type Query {
    users(ids: [ID!]!): [User!]!
    user(id: ID!): User
  }
`;

const resolvers = {
  Query: {
    users: async (parent, args, context) => {
      if (!context.user) throw new AuthenticationError('Authentication required');
      
      const { ids } = args;
      
      // Validate input
      if (!Array.isArray(ids) || ids.length === 0) {
        throw new Error('Invalid IDs array');
      }
      
      if (ids.length > 100) {
        throw new Error('Maximum 100 IDs allowed per request');
      }
      
      // Validate each ID is a valid UUID
      for (const id of ids) {
        if (!validate(id)) {
          throw new Error(`Invalid ID format: ${id}`);
        }
      }
      
      // Apply least privilege - only fetch users the user has access to
      const query = `
        SELECT id, username, email, created_at, is_active 
        FROM users 
        WHERE id = ANY($1) 
        AND is_active = true
      `;
      
      try {
        const result = await pool.query(query, [ids]);
        return result.rows;
      } catch (error) {
        console.error('Database error:', error);
        throw new Error('Failed to fetch users');
      }
    },
    user: async (parent, args, context) => {
      if (!context.user) throw new AuthenticationError('Authentication required');
      
      const { id } = args;
      
      if (!validate(id)) {
        throw new Error('Invalid ID format');
      }
      
      const query = `
        SELECT id, username, email, created_at, is_active 
        FROM users 
        WHERE id = $1 
        AND is_active = true
      `;
      
      try {
        const result = await pool.query(query, [id]);
        return result.rows[0] || null;
      } catch (error) {
        console.error('Database error:', error);
        throw new Error('Failed to fetch user');
      }
    }
  }
};

const authenticateToken = (token) => {
  if (!token) return null;
  
  try {
    const decoded = jwt.verify(token, SECRET_KEY);
    return decoded;
  } catch (error) {
    return null;
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    const token = req.headers.authorization?.replace('Bearer ', '');
    const user = authenticateToken(token);
    
    if (!user) {
      throw new AuthenticationError('Invalid or missing token');
    }
    
    return { user };
  },
  introspection: true,
  playground: true,
  formatError: (error) => {
    console.error('GraphQL Error:', error);
    return new Error('Internal server error');
  }
});

const app = express();

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests'
});

app.use(limiter);

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'OK', timestamp: new Date().toISOString() });
});

// GraphQL endpoint
server.start().then(() => {
  server.applyMiddleware({ app, path: '/graphql' });
});

const PORT = process.env.PORT || 4000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});